css:
.loader {color: var(--loader-color, #9333ea);
  --loader-secondary-color: #f0abfc;
  --loader-bg: #ffffff;
  width: 64px;
  aspect-ratio: 1;
  display: grid;
}.loader:before {content: "";
  border: 8px solid var(--loader-color, #9333ea);
  box-sizing: content-box;
  margin: auto;
  aspect-ratio: 1;
  animation: l7 infinite 1s steps(4,jump-none);
}@keyframes l7 {0% {width: 0% ;
  rotate: 0 }to {width: 75%;
  rotate: 90deg}}
